def classify_age(age: int) -> str:
    if 0 <= age <= 12:
        return "Child"
    elif 13 <= age <= 19:
        return "Teenager"
    elif 20 <= age <= 64:
        return "Adult"
    else:
        return "Senior"

if __name__ == "__main__":
    age = int(input())
    result = classify_age(age)
    print(result)
